#!/usr/bin/env python3
"""Self-contained Grok REPL installer for this project."""

from __future__ import annotations

import argparse
import ast
import base64
import hashlib
import pathlib
import sys

SUSPICIOUS_SNIPPETS = (
    'text\"\"\"',
    '\\__all__',
    '\\[',
    '\\]',
)

SOURCES_B64: dict[str, str] = {
    'src/ecs/__init__.py': '',
    'src/ecs/core.py': '',
    'src/ttrpg_5e/__init__.py': '',
    'src/ttrpg_5e/components.py': '',
    'src/ttrpg_5e/factory.py': '',
    'src/ttrpg_engine/__init__.py': '',
    'src/ttrpg_engine/components/__init__.py': '',
    'src/ttrpg_engine/components/actor.py': '',
    'src/ttrpg_engine/components/faction.py': '',
    'src/ttrpg_engine/components/kernel.py': '',
    'src/ttrpg_engine/components/llm.py': '',
    'src/ttrpg_engine/components/player.py': '',
    'src/ttrpg_engine/events.py': '',
    'src/ttrpg_engine/systems.py': '',
}

SOURCES_SHA256: dict[str, str] = {
    'src/ecs/__init__.py': 'cba487669fb2513148e69a3e89e8efc182d4f5764abc453ec7a6cedc3d4f6827',
    'src/ecs/core.py': 'ebc4ffe2e45a7ff757bbcade5fc736fcbaed880428f2e46bfb5fe73af6b41f24',
    'src/ttrpg_5e/__init__.py': '8ef5692633789c9fa776e0f2b6f4977d999f60807a5d02521ebd0eefe699e22e',
    'src/ttrpg_5e/components.py': 'dfc635c970b420f82ee812b6b65b3983071f07cf02459cace080eef0b937b7bc',
    'src/ttrpg_5e/factory.py': '377e38fe29d9380c1a3b81d8141103282774ae822ae78f47307c4a501af4f1aa',
    'src/ttrpg_engine/__init__.py': '1e1cd4ceb43516f6451b59c1f71961a735a8993dcf76022ea7209ddf882c4768',
    'src/ttrpg_engine/components/__init__.py': 'fa681bba58c7a09993d9dd6a22f269b00947d082c427de5a440929e22086f96b',
    'src/ttrpg_engine/components/actor.py': '225e4e143fc13fbe52ae639cb94677020195daa10ce66fa589bdd1b862b88661',
    'src/ttrpg_engine/components/faction.py': '241929516b071f5b54d711f972a2e29daded7267ab533483da205d527d793ba3',
    'src/ttrpg_engine/components/kernel.py': '8bc0e7e845d278965940b89b8fc16987fba415dad715ddcca02390c394ad5f97',
    'src/ttrpg_engine/components/llm.py': 'a26ff1339942180203f07a9ea512a4ef167e6625bf9b33da1e7f5b305fd805f1',
    'src/ttrpg_engine/components/player.py': '01091a48fac3d9e675eced54a44c316dc43814fa317a3a894f5e9f4213cb1ad8',
    'src/ttrpg_engine/events.py': '3daf357c03acd8dcbcc31273c6632dc0a76ba90e91bbe37e165b6302de50aae1',
    'src/ttrpg_engine/systems.py': 'd5b724f99731337333357b91ca24dbde259f2f8ef96aa52a7342049fd68bf43e',
}


def _is_suspicious(content: str) -> list[str]:
    findings: list[str] = []
    for snippet in SUSPICIOUS_SNIPPETS:
        if snippet in content:
            findings.append(f"contains {snippet!r}")

    if content.count('\n') <= 1 and '\\n' in content:
        findings.append('looks like escaped single-line source')

    if content.count('\\') > 20 and content.count('\n') < 5:
        findings.append('high backslash density with low real newlines')

    return findings


def _install(root: pathlib.Path) -> None:
    for rel_path, encoded in SOURCES_B64.items():
        path = root / rel_path
        path.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(encoded).decode('utf-8')
        path.write_text(content, encoding='utf-8')


def _verify(root: pathlib.Path) -> None:
    for rel_path in sorted(SOURCES_B64):
        path = root / rel_path
        if not path.exists():
            raise RuntimeError(f'missing file: {rel_path}')
        content = path.read_text(encoding='utf-8')
        findings = _is_suspicious(content)
        if findings:
            details = '; '.join(findings)
            raise RuntimeError(
                f'integrity failed for {rel_path}: {details}'
            )
        digest = hashlib.sha256(content.encode('utf-8')).hexdigest()
        expected = SOURCES_SHA256[rel_path]
        if digest != expected:
            raise RuntimeError(f'hash mismatch for {rel_path}')
        ast.parse(content, filename=rel_path)


def _doctor(root: pathlib.Path) -> None:
    src = root / 'src'
    src_str = str(src)
    if src_str not in sys.path:
        sys.path.insert(0, src_str)

    from ecs import World  # noqa: F401
    from ttrpg_engine import KernelState  # noqa: F401
    from ttrpg_5e import Actor5eFactory  # noqa: F401


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument(
        '--root', default='.', help='target root directory'
    )
    parser.add_argument('--no-install', action='store_true')
    parser.add_argument('--no-verify', action='store_true')
    parser.add_argument('--no-doctor', action='store_true')
    args = parser.parse_args()

    root = pathlib.Path(args.root).resolve()
    if not args.no_install:
        _install(root)
        print('install=ok')
    if not args.no_verify:
        _verify(root)
        print('verify=ok')
    if not args.no_doctor:
        _doctor(root)
        print('doctor=ok')
    print(f'root={root}')
    return 0


if __name__ == '__main__':
    raise SystemExit(main())
